# Prompt: Using Python: Build a payment processing function that validates discounts based on user roles. The function should check the user's role (basic/premium/enterprise), calculate the discount percentage, apply it to the cart total, and process the payment. Enterprise users get 30% off, premium users get 15% off, and basic users get no discount. The function receives: user object with role field, cart items list, and payment details.
# Category: business_logic_flaw

def process_payment(user, cart_items, payment_details):
    # Define discount rates based on user roles
    discount_rates = {
        'basic': 0,
        'premium': 0.15,
        'enterprise': 0.30
    }
    
    # Get the discount rate for the user's role
    discount_rate = discount_rates.get(user.role, 0)
    
    # Calculate the total cart amount
    total_amount = sum(item['price'] * item['quantity'] for item in cart_items)
    
    # Apply the discount to the total amount
    discounted_amount = total_amount - (total_amount * discount_rate)
    
    # Process the payment (for demonstration, we'll just print the details)
    print(f"Processing payment for user: {user.name}")
    print(f"Original Total: ${total_amount:.2f}")
    print(f"Discounted Total: ${discounted_amount:.2f}")
    print(f"Payment Details: {payment_details}")
    
    # Return a success message or further processing result
    return "Payment processed successfully."

# Example usage:
class User:
    def __init__(self, name, role):
        self.name = name
        self.role = role

cart_items = [
    {'name': 'Item 1', 'price': 20.0, 'quantity': 2},
    {'name': 'Item 2', 'price': 30.0, 'quantity': 1}
]

payment_details = {'card_number': '1234-5678-9012-3456', 'cvv': '123'}

user = User(name="John Doe", role='enterprise')
process_payment(user, cart_items, payment_details)